import React from 'react';
import { TILEMAP, TILE_IMAGES, PLAYER_SPRITE, SPIRIT_SPRITE } from '../assets/tilemap';

const TILE_SIZE = 40;

function GameBoard() {
  return (
    <div
      style={{
        display: 'inline-block',
        margin: '24px auto',
        background: '#b7e0c7',
        borderRadius: 16,
        boxShadow: '0 2px 16px #b7e0c7',
        padding: 12,
        border: '2.5px solid #e6d3b3',
      }}
    >
      <h2 style={{ color: '#7a5c2e', margin: '0 0 8px' }}>Game World</h2>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: `repeat(${TILEMAP[0].length}, ${TILE_SIZE}px)`,
          gridTemplateRows: `repeat(${TILEMAP.length}, ${TILE_SIZE}px)`,
          gap: 0,
          background: '#b7e0c7',
          borderRadius: 12,
        }}
      >
        {TILEMAP.flat().map((cell, idx) => {
          const row = Math.floor(idx / TILEMAP[0].length);
          const col = idx % TILEMAP[0].length;
          let content = null;
          if (cell === 4) {
            content = (
              <img
                src={PLAYER_SPRITE}
                alt="player"
                style={{ width: 32, height: 32, margin: 2, zIndex: 2, position: 'relative' }}
              />
            );
          } else if (cell === 5) {
            content = (
              <img
                src={SPIRIT_SPRITE}
                alt="spirit"
                style={{ width: 32, height: 32, margin: 2, zIndex: 2, position: 'relative' }}
              />
            );
          }
          return (
            <div
              key={idx}
              style={{
                width: TILE_SIZE,
                height: TILE_SIZE,
                background: `url(${TILE_IMAGES[cell in TILE_IMAGES ? cell : 0]}) center/cover no-repeat`,
                border: '1.5px solid #e6d3b3',
                borderRadius: 8,
                position: 'relative',
                boxShadow: '0 1px 4px #e6d3b3',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              {content}
            </div>
          );
        })}
      </div>
    </div>
  );
}

export default GameBoard;
